#!/bin/bash
# =============================================================================
# LLM Evaluation – Environment Configuration
# =============================================================================
# Sources your personal .env config (generated by setup.sh) and sets all
# environment variables needed by: oellm-cli, OpenJury, vLLM, and any
# HF-based tool.
#
# Usage:
#   source env.sh          # manual
#   (or add to ~/.bashrc via setup.sh)
#
# First-time setup:
#   bash setup.sh
# =============================================================================

_ENV_SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

# Config file: prefer .env, fall back to legacy .env.leonardo
if [[ -f "${_ENV_SCRIPT_DIR}/.env" ]]; then
    _ENV_CONFIG_FILE="${_ENV_SCRIPT_DIR}/.env"
elif [[ -f "${_ENV_SCRIPT_DIR}/.env.leonardo" ]]; then
    _ENV_CONFIG_FILE="${_ENV_SCRIPT_DIR}/.env.leonardo"
else
    echo "❌ Config file not found."
    echo "   Run 'bash ${_ENV_SCRIPT_DIR}/setup.sh' first."
    return 1 2>/dev/null || exit 1
fi

# ═══════════════════════════════════════════════════════════════════
#  Load user config
# ═══════════════════════════════════════════════════════════════════
source "${_ENV_CONFIG_FILE}"

# ═══════════════════════════════════════════════════════════════════
#  Paths
# ═══════════════════════════════════════════════════════════════════
export USER_WORK_DIR="${WORK_DIR}"
export SCRIPTS_DIR="${_ENV_SCRIPT_DIR}"
export PATH="${_ENV_SCRIPT_DIR}/bin:${PATH}"

export EVAL_BASE_DIR="${USER_WORK_DIR}/oellm-evals"
export EVAL_OUTPUT_DIR="${EVAL_BASE_DIR}/outputs"

# Container image (name is cluster-agnostic; location is inside EVAL_BASE_DIR)
export EVAL_CONTAINER_IMAGE="${EVAL_CONTAINER_IMAGE:-eval_env.sif}"
export EVAL_SIF_PATH="${EVAL_BASE_DIR}/${EVAL_CONTAINER_IMAGE}"

# ═══════════════════════════════════════════════════════════════════
#  SLURM settings
# ═══════════════════════════════════════════════════════════════════
export PARTITION="${DEFAULT_PARTITION}"
export ACCOUNT="${SLURM_ACCOUNT}"
export GPUS_PER_NODE="${DEFAULT_GPUS:-1}"
export CPUS_PER_GPU="${DEFAULT_CPUS_PER_GPU:-8}"
export QUEUE_LIMIT="${DEFAULT_QUEUE_LIMIT:-1000}"

# ═══════════════════════════════════════════════════════════════════
#  Container runtime  (from cluster detection via setup.sh)
# ═══════════════════════════════════════════════════════════════════
if [[ -n "${CONTAINER_RUNTIME:-}" ]]; then
    export CONTAINER_RUNTIME
    export CONTAINER_GPU_ARGS="${CONTAINER_GPU_ARGS:-}"

    # Also export as SINGULARITY_ARGS for tools that use that name
    if [[ "${CONTAINER_RUNTIME}" == "singularity" || "${CONTAINER_RUNTIME}" == "apptainer" ]]; then
        export SINGULARITY_ARGS="${CONTAINER_GPU_ARGS}"
        export SINGULARITY_BIND="${EVAL_BASE_DIR}:${EVAL_BASE_DIR},${USER_WORK_DIR}:${USER_WORK_DIR}"
    fi
fi

# ═══════════════════════════════════════════════════════════════════
#  HuggingFace cache  (set by setup.sh)
# ═══════════════════════════════════════════════════════════════════
export HF_HOME="${HF_DATA_DIR}"
export HF_HUB_CACHE="${HF_HOME}/hub"
export HF_XET_CACHE="${HF_HOME}/xet"
export HF_ASSETS_CACHE="${HF_HOME}/assets"
export HUGGINGFACE_HUB_CACHE="${HF_HOME}/hub"
export HUGGINGFACE_ASSETS_CACHE="${HF_HOME}/assets"
export HF_DATASETS_CACHE="${HF_HOME}/datasets"
export TRANSFORMERS_CACHE="${HF_HOME}/hub"

export HF_HUB_DISABLE_PROGRESS_BARS=1
export HF_DATASETS_DISABLE_PROGRESS_BARS=1

# ═══════════════════════════════════════════════════════════════════
#  Offline mode (auto-enabled on compute nodes)
# ═══════════════════════════════════════════════════════════════════
if [[ -n "${SLURM_JOB_ID:-}" ]]; then
    export HF_HUB_OFFLINE=1
    export TRANSFORMERS_OFFLINE=1
    export HF_DATASETS_OFFLINE=1
    export VLLM_NO_USAGE_STATS=1
    export UV_NO_SYNC=1    # Skip uv sync on compute nodes (no PyPI access)
fi

# ═══════════════════════════════════════════════════════════════════
#  SLURM job directories (shared by oellm-cli and OpenJury)
# ═══════════════════════════════════════════════════════════════════
export SLURM_WORK_DIR="${SLURM_WORK_BASE:-${USER_WORK_DIR}/slurm_jobs}"
export SLURM_LOGS_DIR="${SLURM_WORK_DIR}/logs"

# ═══════════════════════════════════════════════════════════════════
#  OpenJury
# ═══════════════════════════════════════════════════════════════════
export OPENJURY_DATA="${USER_WORK_DIR}/openjury-eval-data"
export OPENJURY_PROJECT_DIR="${USER_WORK_DIR}/OpenJury"

# ═══════════════════════════════════════════════════════════════════
#  UV (Python package manager)
# ═══════════════════════════════════════════════════════════════════
export UV_LINK_MODE="copy"

# ═══════════════════════════════════════════════════════════════════
#  Time limit
# ═══════════════════════════════════════════════════════════════════
export TIME_LIMIT="${DEFAULT_TIME_LIMIT:-00:30:00}"

# ═══════════════════════════════════════════════════════════════════
#  Create directories (only once per session)
# ═══════════════════════════════════════════════════════════════════
if [[ -z "${_CLUSTER_ENV_LOADED:-}" ]]; then
    mkdir -p "${EVAL_BASE_DIR}" "${EVAL_OUTPUT_DIR}" \
             "${HF_HUB_CACHE}" "${HF_DATASETS_CACHE}" \
             "${HF_ASSETS_CACHE}" "${HF_XET_CACHE}" \
             "${OPENJURY_DATA}" "${SLURM_WORK_DIR}/logs" \
             "${SLURM_WORK_DIR}/oellm-cli" \
             "${SLURM_WORK_DIR}/openjury" 2>/dev/null
    export _CLUSTER_ENV_LOADED=1
fi

# ═══════════════════════════════════════════════════════════════════
#  Summary (only in interactive shells)
# ═══════════════════════════════════════════════════════════════════
if [[ $- == *i* ]] || [[ -n "${ENV_VERBOSE:-}" ]]; then
    _cluster_label="${CLUSTER_NAME:-local}"
    if [[ -n "${SLURM_JOB_ID:-}" ]]; then
        echo "✅ Environment loaded [${_cluster_label}] (OFFLINE – job ${SLURM_JOB_ID})"
    else
        echo "✅ Environment loaded [${_cluster_label}] (ONLINE – login node)"
    fi
    echo "   User:    ${ENV_USER:-${USER}}  Account: ${ACCOUNT:-n/a}"
    echo "   HF_HOME: ${HF_HOME}  (${CACHE_MODE:-per-user})"
fi
